// Sort by the underlying chat message's created_at (the event time), NOT
// rr.created_at (the scan time). The background drain workflow analyzes
// historical messages in arbitrary order, so rr.created_at can put a
// finding for an old message ahead of one for a recent message — which is
// exactly the "random-seeming" order users see in Recent Findings.
// Cursor is (cm.created_at, rr.id) for stable pagination.
func (q *Queries) ListRiskResultsByProjectFound(ctx context.Context, arg ListRiskResultsByProjectFoundParams) ([]ListRiskResultsByProjectFoundRow, error) {
	rows, err := q.db.Query(ctx, listRiskResultsByProjectFound,
		arg.ProjectID,
		arg.CursorMessageCreatedAt,
		arg.CursorID,
		arg.PageLimit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListRiskResultsByProjectFoundRow
	for rows.Next() {
		var i ListRiskResultsByProjectFoundRow
		if err := rows.Scan(
			&i.ID,
			&i.ProjectID,
			&i.OrganizationID,
			&i.RiskPolicyID,
			&i.RiskPolicyVersion,
			&i.ChatMessageID,
			&i.Source,
			&i.Found,
			&i.RuleID,
			&i.Description,
			&i.Match,
			&i.StartPos,
			&i.EndPos,
			&i.Confidence,
			&i.Tags,
			&i.DeadLetterReason,
			&i.CreatedAt,
			&i.ChatID,
			&i.MessageCreatedAt,
			&i.ChatTitle,
			&i.ChatUserID,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const listRiskResultsGroupedByChat = `-- name: ListRiskResultsGroupedByChat :many
SELECT
    cm.chat_id
  , c.title AS chat_title
  , c.external_user_id AS chat_user_id
  , COUNT(*)::BIGINT AS findings_count
  , MAX(rr.created_at)::TIMESTAMPTZ AS latest_detected
FROM risk_results rr
JOIN chat_messages cm ON cm.id = rr.chat_message_id
LEFT JOIN chats c ON c.id = cm.chat_id AND c.deleted IS FALSE
JOIN risk_policies rp ON rp.id = rr.risk_policy_id AND rp.deleted IS FALSE AND rp.enabled IS TRUE
WHERE rr.project_id = $1
  AND rr.found IS TRUE
  AND ($2::uuid IS NULL OR cm.chat_id <= $2::uuid)
GROUP BY cm.chat_id, c.title, c.external_user_id
ORDER BY cm.chat_id DESC
LIMIT $3
`

type ListRiskResultsGroupedByChatParams struct {
	ProjectID uuid.UUID
	Cursor    uuid.NullUUID
	PageLimit int32
}

type ListRiskResultsGroupedByChatRow struct {
	ChatID         uuid.UUID
	ChatTitle      pgtype.Text
	ChatUserID     pgtype.Text
	FindingsCount  int64
	LatestDetected pgtype.Timestamptz
}

func (q *Queries) ListRiskResultsGroupedByChat(ctx context.Context, arg ListRiskResultsGroupedByChatParams) ([]ListRiskResultsGroupedByChatRow, error) {
	rows, err := q.db.Query(ctx, listRiskResultsGroupedByChat, arg.ProjectID, arg.Cursor, arg.PageLimit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListRiskResultsGroupedByChatRow
	for rows.Next() {
		var i ListRiskResultsGroupedByChatRow
		if err := rows.Scan(
			&i.ChatID,
			&i.ChatTitle,
			&i.ChatUserID,
			&i.FindingsCount,
			&i.LatestDetected,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const updateRiskPolicy = `-- name: UpdateRiskPolicy :one
UPDATE risk_policies
SET name = $1
  , sources = $2
  , presidio_entities = $3
  , prompt_injection_rules = $4
  , enabled = $5
  , action = $6
  , auto_name = $7
  , user_message = $8
  , version = CASE
      WHEN sources IS DISTINCT FROM $2
        OR presidio_entities IS DISTINCT FROM $3
        OR prompt_injection_rules IS DISTINCT FROM $4
        OR enabled IS DISTINCT FROM $5
        OR action IS DISTINCT FROM $6
      THEN version + 1
      ELSE version
    END
  , updated_at = clock_timestamp()
WHERE id = $9
  AND project_id = $10
  AND deleted IS FALSE
RETURNING id, project_id, organization_id, enabled, name, sources, presidio_entities, prompt_injection_rules, action, auto_name, user_message, version, created_at, updated_at, deleted_at, deleted
`

type UpdateRiskPolicyParams struct {
	Name                 string
	Sources              []string
	PresidioEntities     []string
	PromptInjectionRules []string
	Enabled              bool
	Action               string
	AutoName             bool
	UserMessage          pgtype.Text
	ID                   uuid.UUID
	ProjectID            uuid.UUID
}

func (q *Queries) UpdateRiskPolicy(ctx context.Context, arg UpdateRiskPolicyParams) (RiskPolicy, error) {
	row := q.db.QueryRow(ctx, updateRiskPolicy,
		arg.Name,
		arg.Sources,
		arg.PresidioEntities,
		arg.PromptInjectionRules,
		arg.Enabled,
		arg.Action,
		arg.AutoName,
		arg.UserMessage,
		arg.ID,
		arg.ProjectID,
	)
	var i RiskPolicy
	err := row.Scan(
		&i.ID,
		&i.ProjectID,
		&i.OrganizationID,
		&i.Enabled,
		&i.Name,
		&i.Sources,
		&i.PresidioEntities,
		&i.PromptInjectionRules,
		&i.Action,
		&i.AutoName,
		&i.UserMessage,
		&i.Version,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.DeletedAt,
		&i.Deleted,
	)
	return i, err
}
